SELECT AVG(cgpa) AS average_cgpa, SUM(total_credits) AS total_credits_count
FROM gpa_calculations
WHERE student_id = 0;

SELECT COUNT(DISTINCT student_id) AS students_with_a_grade
FROM grades
WHERE grade = 'A';

SELECT semester, AVG(cgpa) AS average_cgpa, COUNT(student_id) AS number_of_students
FROM gpa_calculations
GROUP BY semester;

SELECT MAX(grade_point) AS max_grade_point
FROM transcripts
WHERE semester = 'Fall 2023';

SELECT AVG(sgpa) AS average_sgpa
FROM gpa_calculations
WHERE semester = 'Fall 2023';
